import{_ as a,o as n,c as s,ag as i}from"./chunks/framework.CMWvBNEy.js";const u=JSON.parse('{"title":"Agentic Harness: Workflow Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/agentic-usage.md","filePath":"guide/agentic-usage.md"}'),r={name:"guide/agentic-usage.md"};function t(o,e,l,p,c,d){return n(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="agentic-harness-workflow-overview" tabindex="-1">Agentic Harness: Workflow Overview <a class="header-anchor" href="#agentic-harness-workflow-overview" aria-label="Permalink to &quot;Agentic Harness: Workflow Overview&quot;">​</a></h1><p>Mocking GUI goes beyond being a simple library — it is an <strong>Agentic Harness</strong> system where a team of specialized AI agents builds and maintains an optimized mocking ecosystem for your environment.</p><p>The harness operates across two professional tracks: core library development and solution engineering. All agents work with deep expertise in Mocking GUI&#39;s core architecture and browser/frontend engineering.</p><h2 id="🏗️-1-core-development-track" tabindex="-1">🏗️ 1. Core Development Track <a class="header-anchor" href="#🏗️-1-core-development-track" aria-label="Permalink to &quot;🏗️ 1. Core Development Track&quot;">​</a></h2><p>An internal engineering pipeline responsible for the completeness and architecture of the Mocking GUI library itself.</p><h3 id="primary-workflow-harness-dev-pipeline" tabindex="-1">Primary Workflow: <code>/harness-dev-pipeline</code> <a class="header-anchor" href="#primary-workflow-harness-dev-pipeline" aria-label="Permalink to &quot;Primary Workflow: \`/harness-dev-pipeline\`&quot;">​</a></h3><ol><li><strong>Scenario-Driven Design</strong>: Define how a feature behaves in code before implementation, and validate architectural consistency upfront.</li><li><strong>High-Precision Engineering</strong>: Implement stable, extensible core logic using TypeScript&#39;s strict type system.</li><li><strong>Integrated Quality Gate</strong>: Changes must pass a rigorous verification pipeline combining Lint, Vitest, and Build before release eligibility.</li><li><strong>Documentation Auto-Sync</strong>: The run&#39;s draft spec is promoted to the canonical spec registry on approval, and user guides are kept up-to-date in real time.</li></ol><h4 id="artifact-trail" tabindex="-1">Artifact Trail <a class="header-anchor" href="#artifact-trail" aria-label="Permalink to &quot;Artifact Trail&quot;">​</a></h4><p>Every run of <code>/harness-dev-pipeline</code> creates one dated folder under <code>agent-artifacts/workstreams/</code>, and nothing is written outside it while the run is in progress:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-artifacts/workstreams/2026-07-01-ssr-state-sync/</span></span>
<span class="line"><span>├── manifest.yaml            # current phase / status — the run&#39;s state machine</span></span>
<span class="line"><span>├── spec.md                  # Phase 1 deliverable: the draft feature spec</span></span>
<span class="line"><span>├── approvals/</span></span>
<span class="line"><span>│   ├── phase1-gate.md       # who approved Phase 1, when, and why</span></span>
<span class="line"><span>│   ├── phase2-gate.md</span></span>
<span class="line"><span>│   ├── phase3-gate.md</span></span>
<span class="line"><span>│   └── phase4-gate.md</span></span>
<span class="line"><span>├── executions/</span></span>
<span class="line"><span>│   ├── phase1-analysis.md   # what each phase actually did</span></span>
<span class="line"><span>│   ├── phase2-implementation.md</span></span>
<span class="line"><span>│   ├── phase3-verification.md</span></span>
<span class="line"><span>│   └── phase4-documentation.md</span></span>
<span class="line"><span>└── reports/</span></span>
<span class="line"><span>    ├── integrity-report.md  # final Lint/Vitest/Build results</span></span>
<span class="line"><span>    └── release-briefing.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>Once the spec is approved, it is copied to <code>agent-artifacts/specs/{feature}.md</code> as the living, canonical version (the run&#39;s <code>spec.md</code> stays frozen as history). Any architecture decision made along the way is recorded once, globally, in <code>agent-artifacts/decisions/ADR-{NNNN}-{slug}.md</code> and indexed in <code>decisions/INDEX.md</code> — so a decision made in one run is discoverable and reusable by every later run. Bug fixes and small changes skip this full structure and instead get a single <code>agent-artifacts/workstreams/{date}-{slug}/RUN.md</code> covering decision, approval, and log in one file.</p><h2 id="🚀-2-solution-engineering-track" tabindex="-1">🚀 2. Solution Engineering Track <a class="header-anchor" href="#🚀-2-solution-engineering-track" aria-label="Permalink to &quot;🚀 2. Solution Engineering Track&quot;">​</a></h2><p>A strategic support pipeline for successfully adopting Mocking GUI in user projects and building a productive mock ecosystem.</p><h3 id="primary-workflow-technical-solution-support" tabindex="-1">Primary Workflow: <code>/technical-solution-support</code> <a class="header-anchor" href="#primary-workflow-technical-solution-support" aria-label="Permalink to &quot;Primary Workflow: \`/technical-solution-support\`&quot;">​</a></h3><ol><li><strong>Deterministic Project Audit</strong>: Precisely analyzes the target project&#39;s environment (package manager, framework, API scale) to formulate the optimal onboarding strategy.</li><li><strong>Adaptive Infrastructure Setup</strong>: Integrates Service Worker (MSW) and applies browser-level network optimization based on audit results.</li><li><strong>Professional Mock Architecture</strong>: Applies the Handlers / Constants / Factories layer separation principle for a maintainable data environment.</li><li><strong>Skill &amp; Reference Deployment</strong>: Distributes project-specific agent skill sets and technical references to maximize collaboration efficiency.</li></ol><h2 id="🧠-shared-knowledge-base" tabindex="-1">🧠 Shared Knowledge Base <a class="header-anchor" href="#🧠-shared-knowledge-base" aria-label="Permalink to &quot;🧠 Shared Knowledge Base&quot;">​</a></h2><p>Both tracks serve different purposes but share the same level of expertise in <strong>Mocking GUI interfaces and frontend engineering</strong>:</p><ul><li><strong>Service Worker &amp; Browser</strong>: Internals of request interception, caching, and latency simulation in the browser network stack.</li><li><strong>Mocking GUI Core Interface</strong>: Deep understanding of core specs such as <code>HandlerConfigOption</code>, <code>responseVariants</code>, and <code>responseVariantsFn</code>.</li><li><strong>Professional Engineering</strong>: Immutable state management with Immer, deterministic data generation with Faker seed patterns, and relational data integrity.</li></ul>`,18)])])}const m=a(r,[["render",t]]);export{u as __pageData,m as default};
